window.__QUIZ_DATA__=[{"id":"objective>Chemistry>2021>1","subject":"Chemistry","year":"2021","type":"Objective","topic":"BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : PROTEINS","question":"The hydrolysis of protein by dilute minerals acids produces","images":[],"options":{"A":"sucrose","B":"glucose","C":"amino acids","D":"fatty acids"},"answer":"C","explanation":"Proteins are large molecules made up of amino acids. When proteins are hydrolyzed, or chemically broken down, by dilute mineral acids, the result is a mixture of amino acids. Therefore, the correct answer is 'amino acids'. The other options (sucrose, glucose, and fatty acids) are not produced by the hydrolysis of proteins.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2021>2","subject":"Chemistry","year":"2021","type":"Objective","topic":"ACIDS, BASES AND SALTS : ACIDS","question":"Which of the following oxides causes acids rain ?","images":[],"options":{"A":"CO","B":"NO","C":"H2O2","D":"NO2"},"answer":"D","explanation":"NO2 is an acidic gas i.e acid anhydride. It dissolve in rain (water) to give a mixed acid  NO2 + H2O \u2192 HNO3 + HNO2","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2021>3","subject":"Chemistry","year":"2021","type":"Objective","topic":"CHEMISTRY OF CARBON COMPOUNDS : DETERMINATION OF EMPIRICAL AND MOLECULAR FORMULAE AND MOLECULAR STRUCTURES OF ORGANIC COMPOUNDS","question":"The ratio of carbon atoms to hydrogen atoms in a hydrocarbon is 1:2, if its molecular mass is 56 what is the molecular formular?","images":[],"options":{"A":"C3H6","B":"C4H8","C":"C2H4","D":"CH2"},"answer":"B","explanation":"The ratio means the empirical fomula of the hyrocarbon  [CH2] = relative molecular mass (RMM)  (12 + 1 x 2) = 56  [12 + 2]n = 56  14n = 56  n = 56/14  n = 4  The molecular formula is (CH2)4  C4H8","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2021>4","subject":"Chemistry","year":"2021","type":"Objective","topic":"STOICHIOMETRY AND CHEMICAL REACTIONS : MOLE RATIOS","question":"what is the relative molecular mass of the compound below?    [H = 1, C = 12.0, O = 16.0]","images":["data:image/png;base64,"],"options":{"A":"137","B":"136","C":"64","D":"59"},"answer":"B","explanation":"The molecular formular is C6H5COOCH3  RMM = (12x6) + (1x5) + 12 + 16 + 16 + 12 + (1x3)   = 72 + 5 + 12 + 32 + 12 + 3   = 136g/mol","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2021>5","subject":"Chemistry","year":"2021","type":"Objective","topic":"REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.","question":"Cathodic protection of metals is based on","images":[],"options":{"A":"standard electrode potential of hydrogen","B":"it electrical conductivity","C":"nature of oxides formed","D":"relative tendencies of oxidation"},"answer":"D","explanation":"corrosion is a destructive phenomenoen  that occur whe metals are exposed to the environment.the reaction between air, water and the metal form a stable compound of metal.  This reaction depends on the reactivity of the metal","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2021>6","subject":"Chemistry","year":"2021","type":"Objective","topic":"NON METALS AND THEIR COMPOUNDS : HALOGENS","question":"If humid air is polluted by chlorine discharge the air can be restored by sprinkling","images":[],"options":{"A":"solid MnO2","B":"acidified KMnO4","C":"acidified FeSO4","D":"saturated NaCl"},"answer":"B","explanation":"Chlorine is a toxic gas and when it pollutes the air, it can be neutralized by using acidified KMnO4. The reaction between chlorine and acidified KMnO4 results in the formation of chloride ions, manganese(II) ions, and water, which are harmless. This is why acidified KMnO4 is used to restore air polluted by chlorine discharge.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2021>7","subject":"Chemistry","year":"2021","type":"Objective","topic":"CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS","question":"The alkanol represented by the structure below is","images":["data:image/png;base64,"],"options":{"A":"primary and dihydric","B":"secondary and monohydric","C":"tertiary and dihydric","D":"secondary and dihydric"},"answer":"A","explanation":"It has only one alkyl group and dihydric because it has two hydroxyl groups","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2021>8","subject":"Chemistry","year":"2021","type":"Objective","topic":"SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES","question":"Which of the pairs of compounds would form a precipitate when an aqueous solution is involved","images":[],"options":{"A":"NaCl and KNO3","B":"KCL and NaNO3","C":"K2SO4 and BaCl2","D":"NH2NO3 and NaCO3"},"answer":"C","explanation":"Double composition reaction is a reaction between two soluble salts to give on soluble and on insoluble salt is the precipitate   K2SO4 + BaCl2\u2192KCl + Ba SO4  BaSO4 is insoluble because all trioxosulphate VI slats are soluble except Pb2+,Cu2+,Ca2+, Ba2+","marks":"1","difficulty":"3"},{"id":"objective>Chemistry>2021>9","subject":"Chemistry","year":"2021","type":"Objective","topic":"CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS","question":"Which of the graphs illustrates the variation of the rate of evolution of a gas from a given length of magnesium ribbon(y-axis) with increase in the concentration of the acid added (x-axis)","images":["data:image/jpeg;base64,"],"options":{"A":"I","B":"II","C":"III","D":"IV"},"answer":"A","explanation":"Graph I illustrates the variation of the rate of evolution of a gas from a given length of magnesium ribbon(y-axis) with increase in the concentration of the acid added (x-axis).","marks":"1","difficulty":"3"},{"id":"objective>Chemistry>2021>10","subject":"Chemistry","year":"2021","type":"Objective","topic":"ACIDS, BASES AND SALTS : CONCEPT OF PH","question":"Which of the graphs illustrates the variation of the pH of a given volume of strong acid solution (y-axis) with the volume of strong base titrated against its (x-axis)?","images":["data:image/jpeg;base64,"],"options":{"A":"I","B":"II","C":"III","D":"IV"},"answer":"A","explanation":"Graph I. For a reaction between strong acid and strong base , there is a rapid change in PH from 3.5 to 9.5(y-axis) when the quantity of base (x-axis) is added","marks":"1","difficulty":"3"},{"id":"objective>Chemistry>2021>11","subject":"Chemistry","year":"2021","type":"Objective","topic":"SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES","question":"Which of the graphs illustrates variation of the solubility of a salt in water (y-axis) with increase in temperature (x-axis) if the dissolution process is exothermic","images":["data:image/jpeg;base64,"],"options":{"A":"I","B":"II","C":"III","D":"IV"},"answer":"D","explanation":"Graph IV. Increase in temperature leads to increase in rate of reaction . increase in temperature will reduce the time in bond breaking which in turn leads to increase in solubility","marks":"1","difficulty":"3"},{"id":"objective>Chemistry>2021>12","subject":"Chemistry","year":"2021","type":"Objective","topic":"CHEMISTRY OF CARBON COMPOUNDS : ALKENES","question":"The formation of ethene from dehydration of ethanol can be described as","images":[],"options":{"A":"an addition reaction","B":"an elimination reaction","C":"an oxidation reaction","D":"a substitution reaction"},"answer":"B","explanation":"C2H5 H2SO4\u2192-H2O  C2H4  this is the removal of H2O from ethanol which is elimination method","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2021>13","subject":"Chemistry","year":"2021","type":"Objective","topic":"NON METALS AND THEIR COMPOUNDS : NITROGEN","question":"Which of the following gases is highly soluble in water at room temperature?","images":[],"options":{"A":"Ammonia","B":"carbon(IV) oxide","C":"chlorine","D":"Nitrogen"},"answer":"A","explanation":"Ammonia is highly soluble in water at room temperature. This is due to the fact that ammonia is a polar molecule and can form hydrogen bonds with water molecules, which leads to its high solubility.","marks":"1","difficulty":"1"},{"id":"objective>Chemistry>2021>14","subject":"Chemistry","year":"2021","type":"Objective","topic":"CHEMICAL BONDS : COVALENT BONDS AND COMPOUNDS.","question":"A molecule of phosphorus is","images":[],"options":{"A":"diatomic","B":"triatomic","C":"tetra-atomic","D":"monoatomic"},"answer":"C","explanation":"A molecule of phosphorus is tetra-atomic. This means it is composed of four atoms. In its most stable form, phosphorus exists as P4 molecules, where four phosphorus atoms form a tetrahedral structure.","marks":"1","difficulty":"1"},{"id":"objective>Chemistry>2021>15","subject":"Chemistry","year":"2021","type":"Objective","topic":"ACIDS, BASES AND SALTS : SALTS","question":"The common method of preparing insoluble salts is by","images":[],"options":{"A":"filtration","B":"decomposition","C":"neutralization","D":"double decomposition"},"answer":"D","explanation":"Insoluble salts are prepared by  - direct combination of constituents elements   F3 + S \u2192FeS    - Double decomposition reaction : this is a reaction between two soluble salts to give one soluble and one insoluble salt which is the precipate   K2SO4 + BaCl \u2192KCl(soluble) + BaSO4(insoluble)","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2021>16","subject":"Chemistry","year":"2021","type":"Objective","topic":"STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.","question":"What is the number of moles of oxygen would exert a pressure of 10 atm at 320oK in an 8.2dm3 cylinder?  [R = 0.82 atm dm3 ml-1K-1]","images":[],"options":{"A":"0.32","B":"1.56","C":"3.13","D":"31.25"},"answer":"C","explanation":"n = ?, p = 10 atm, v = 8.2dm3, R = 0.082  T = 320k  recall, Pv = nKT  n=PVRT  =10x8.20.082x320  n = 3.13","marks":"1","difficulty":"3"},{"id":"objective>Chemistry>2021>17","subject":"Chemistry","year":"2021","type":"Objective","topic":"ACIDS, BASES AND SALTS : DELIQUESCENT, EFFLORESCENT AND HYGROSCOPIC COMPOUND.","question":"The basic property of salt as a drying agent is","images":[],"options":{"A":"efflorescence","B":"high melting point","C":"hygroscope","D":"low solubility"},"answer":"C","explanation":"The basic property of salt as a drying agent is its hygroscopic nature. Hygroscopic substances have the ability to attract and hold water molecules from the surrounding environment. This is achieved through either absorption or adsorption of the water molecules.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2021>18","subject":"Chemistry","year":"2021","type":"Objective","topic":"METALS AND THEIR COMPOUNDS : PROPERTIES AND USES OF COPPER AND ITS COMPOUNDS.","question":"What would be observed when aqueous ammonia is added in drops and then in excess to a solution of copper(II)ions?","images":[],"options":{"A":"Blue precipitate is formed which is soluble in excess ammonia","B":"brick red precipitate is produced which is insoluble in excess ammonia","C":"white precipitate is formed which is soluble in excess ammonia","D":"green precipitate is formed wich is insoluble in excess ammonia"},"answer":"A","explanation":"CU2+ forms a deep blue precipitate which is soluble in excess NH4OH    Blue precipitate formed which dissolved in excess aqueous ammonia to form a dark blue solution.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2021>19","subject":"Chemistry","year":"2021","type":"Objective","topic":"ACIDS, BASES AND SALTS : SALTS","question":"When CuSO4(aq) is added to Pb(NO3)(aq)","images":[],"options":{"A":"There would be no visible change","B":"a blue precipitate would be formed","C":"The resulting solution would be colourless","D":"A white precipitate would formed"},"answer":"D","explanation":"When CuSO4(aq) is added to Pb(NO3)2(aq), a white precipitate of lead(II) sulfate is formed. This is due to a double displacement reaction where lead ions (Pb2+) and sulfate ions (SO4 2-) combine to form the insoluble lead(II) sulfate.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2021>20","subject":"Chemistry","year":"2021","type":"Objective","topic":"CHEMISTRY OF CARBON COMPOUNDS : CLASSIFICATION","question":"How many carbon atoms does the parent chain contain?","images":["data:image/png;base64,"],"options":{"A":"5","B":"4","C":"3","D":"2"},"answer":"B","explanation":"The largest carbon chain illustrated above is 4. The parent chain contain 4 carbon.","marks":"1","difficulty":"1"},{"id":"objective>Chemistry>2021>21","subject":"Chemistry","year":"2021","type":"Objective","topic":"STATES OF MATTER : GASES","question":"Under which condition of pressure(p) and temperature (T) would be volume of an inflated ballon increase? when","images":[],"options":{"A":"Both T and P are increased","B":"Both T and P decrease","C":"T is increased and P is decreased","D":"T is decreased and P is increased"},"answer":"C","explanation":"V x T, also V \u03b1 1/p  When volume increases, temperature also increases and pressure reduces as stated by charles and Boyle laws.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2021>22","subject":"Chemistry","year":"2021","type":"Objective","topic":"STATES OF MATTER : GASES","question":"The collision between ideal gas molecules are considered to be perfectly elastic because","images":[],"options":{"A":"They collide without losing energy","B":"They randomly in straight line","C":"Their average kinetic energy is variables","D":"The distance between them is large compared to their sizes"},"answer":"A","explanation":"Gas molecules collide with one another and separate after collision . Both their momentum and kinetic energy are conserved . This known as elastic collision.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2021>23","subject":"Chemistry","year":"2021","type":"Objective","topic":"PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS","question":"Elements with ionization energies would","images":[],"options":{"A":"lose electrons easily","B":"have large atomic radii","C":"have effective nuclear charges","D":"have low atomic numbers"},"answer":"C","explanation":"ionization energy required is the energy required to remove one mole of electron from a gaseous atom in order to make it a gaseous ion . It depends on nuclear shield and the electrostatic force of attraction between the nucleus (positive) and the outermost electron (negative ) element with higher nuclear charge have higher electrostatic force of attraction which leads to higher ionization energy","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2021>24","subject":"Chemistry","year":"2021","type":"Objective","topic":"PERIODIC CHEMISTRY : ELEMENTS OF THE FIRST TRANSITION SERIES.","question":"Which of the following statement about Group VII elements is correct ?","images":[],"options":{"A":"they are present in the same physical state","B":"they are strong reducing agent","C":"their reactivity decreases down the group","D":"they exist as monoatomic molecules"},"answer":"C","explanation":"Group 7 element properties   - Diatomic   -highly oxidizing agent  - electronegativity decreases down the group (reactivity)  - Density increases down th group (physical property)  - colour darkens down the group","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2021>25","subject":"Chemistry","year":"2021","type":"Objective","topic":"REDOX REACTIONS : ELECTROCHEMICAL CELLS","question":"Which of the following cell notation represents the diagram?","images":["data:image/jpeg;base64,"],"options":{"A":"B2/B//AA3+","B":"A3+/A//B/B+","C":"B/B2+//A/A3+","D":"A/A3-//B2+/B"},"answer":"D","explanation":"Oxidation takes place at the anode i.e is loss of electrons while reduction occur at the cathode i.e gain of electrons.  The electrochemical cell can be symbolically represented  as Anode /Anode solution//cathode solution /cathode A/A3-//B2+/B","marks":"1","difficulty":"3"},{"id":"objective>Chemistry>2021>26","subject":"Chemistry","year":"2021","type":"Objective","topic":"REDOX REACTIONS : ELECTROCHEMICAL CELLS","question":"Which of the following half reaction equation represent the reaction at the cathode?","images":[],"options":{"A":"A3+(aq) + 3e- \u2192A(g)","B":"B2+(aq) + 2e-\u2192B(x)","C":"A(g) \u2192 A+(aq) + 3e-","D":"B(g) \u2192B+(aq) + 2e-"},"answer":"A","explanation":"In electrochemistry, the cathode is the electrode where reduction occurs. Reduction is a process where a species gains electrons. Therefore, the correct half-reaction should depict a species gaining electrons. A3+(aq) + 3e- \u2192A(g) correctly shows this process.","marks":"1","difficulty":"3"},{"id":"objective>Chemistry>2021>27","subject":"Chemistry","year":"2021","type":"Objective","topic":"PERIODIC CHEMISTRY : DIFFERENT CATEGORIES OF ELEMENTS IN THE PERIODIC TABLE","question":"The reactivity of the fluorine is high because of","images":[],"options":{"A":"its high electronegativity","B":"The small size of the fluorine atom","C":"The availability of b-orbital","D":"The Strong F-F bond"},"answer":"A","explanation":"Fluorine is the most electronegative element in the periodic table. Electronegativity is a measure of the tendency of an atom to attract a bonding pair of electrons. The high electronegativity of fluorine makes it highly reactive.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2021>28","subject":"Chemistry","year":"2021","type":"Objective","topic":"REDOX REACTIONS : ELECTROLYSIS","question":"How many coulombs of electricity would liberate 1.08g of Ag from a solution of silver salt?  [Ag = 108.0, 1F = 96500C]","images":[],"options":{"A":"96500C","B":"9650C","C":"965C","D":"9.65C"},"answer":"C","explanation":"Ag+ + e- \u2192Ag  1 mole  of Ag+ requires 1 faraday(9650C)  108g \u219296500  1.08 \u2192Q  Cross multiply108Q = 1.08 x 96500  C=1.08x965001.08  Q = 965C","marks":"1","difficulty":"3"},{"id":"objective>Chemistry>2021>29","subject":"Chemistry","year":"2021","type":"Objective","topic":"STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.","question":"Which of the following quantities is the same for one mole of Br2(l) and one mole of He(g)?","images":[],"options":{"A":"Number of molecules","B":"Number of atoms","C":"Total mass of the particles","D":"Volume occupied at s.t.p."},"answer":"A","explanation":"Number of molecules. The number of molecules in a given sample, you can use the relationship between moles, Avogadro's number, and the mass of the substance.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2021>30","subject":"Chemistry","year":"2021","type":"Objective","topic":"ACIDS, BASES AND SALTS : ACIDS","question":"Which of the following acids is dibasic?","images":[],"options":{"A":"hydrochloric acid","B":"Trioxosulphate (IV) Acid","C":"Dioxonitrate (III) acid","D":"Ethanoic acid"},"answer":"B","explanation":"A dibasic acid has two replaceable hydrogen atoms. it gives two free hydrogen ions in solution for each molecule of acid ionized.  The correct is H2SO3.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2021>31","subject":"Chemistry","year":"2021","type":"Objective","topic":"ACIDS, BASES AND SALTS : ACIDS","question":"Bees inject an acidic substance when they sting. Which of the following chemical could be used to treat bee stings?","images":[],"options":{"A":"CH3COOH","B":"NaHCO3","C":"C2H5OH","D":"H2O2"},"answer":"B","explanation":"Bee stings are acidic in nature because they contain formic acid. To neutralize the effect of the sting, a basic substance should be used. Sodium bicarbonate (NaHCO3), also known as baking soda, is a basic substance and can neutralize the acidic effect of the bee sting. Therefore, the correct answer is 'NaHCO3'.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2021>32","subject":"Chemistry","year":"2021","type":"Objective","topic":"STOICHIOMETRY AND CHEMICAL REACTIONS : SOLUTIONS","question":"What is the concentration of a solution which contains 0.28g of potassium hydroxide in 100cm3 of solution?","images":[],"options":{"A":"0.01 mol dm-3","B":"0.05mol dm-3","C":"0.10 mol dm-3","D":"0.50mol dm-3"},"answer":"B","explanation":"Conc. in g/dm3 =mass/volume   = 0.28/0.1 = 2.8g/dm3  concinmolddm3=conc.ing/dm3reactive molecular mass   = 2.8/58 = 0.05mol dm-3","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2021>33","subject":"Chemistry","year":"2021","type":"Objective","topic":"CHEMISTRY OF CARBON COMPOUNDS : DETERMINATION OF EMPIRICAL AND MOLECULAR FORMULAE AND MOLECULAR STRUCTURES OF ORGANIC COMPOUNDS","question":"What is the empirical formula of hydrocarbon containing 0.160 moles of carbon and 0.640 moles of hydrogen?","images":[],"options":{"A":"CH2","B":"CH3","C":"CH4","D":"C2H4"},"answer":"C","explanation":"CHmoles0.160.64molar ratio0.16/0.160.64/0.1614  The empirical formular is CH4","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2021>34","subject":"Chemistry","year":"2021","type":"Objective","topic":"PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS","question":"Which of the following has the highest ionic radius ?","images":[],"options":{"A":"S2-","B":"Cl-","C":"K-","D":"Ca2+"},"answer":"A","explanation":"The ionic radius of an ion is determined by the number of electron shells it has and the effective nuclear charge it experiences. Among the given options, S2- has the highest ionic radius because it has the most electron shells and the lowest effective nuclear charge.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2021>35","subject":"Chemistry","year":"2021","type":"Objective","topic":"PERIODIC CHEMISTRY : PERIODIC LAW","question":"Which of the following statement is correct about ionization energy? it","images":[],"options":{"A":"decrease across the periods","B":"result in the formation of an atom","C":"causes metallic nuclei to disintegrate","D":"decrease down the group"},"answer":"D","explanation":"ionization energy is the energy needed to remove one mole of electron from a gaseous atom in order to make it a gaseous ion. it increases  across the period and decreases down the group.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2021>36","subject":"Chemistry","year":"2021","type":"Objective","topic":"ACIDS, BASES AND SALTS : SALTS","question":"Potassium Trioxonitrate (V) can be obtained from its solution by","images":[],"options":{"A":"distillation","B":"evaporation","C":"crystallization","D":"Filtration"},"answer":"C","explanation":"KNO3 is a soluble salt just as NaCl . NaCl can be recovered from a solution by evaporation to dryness because it is thermoresistant salt i.e normally stable . On the other hand KNO3 cannot be recovered through evaporation because it is decomposes upon heating  KNO3 \u2206\u2192heat  KNO2 + O2  hence is recovered through Crystallization","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2021>37","subject":"Chemistry","year":"2021","type":"Objective","topic":"STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.","question":"An element Q contains 69% of 63Q and 31% in 65Q. What is the relative atomic mass of Q?","images":[],"options":{"A":"63.0","B":"63.6","C":"65.0","D":"69.0"},"answer":"B","explanation":"The relative atomic mass of an element is calculated by taking the weighted average of the atomic masses of its isotopes. In this case, the element Q contains 69% of 63Q and 31% of 65Q. So, the relative atomic mass of Q is (0.69 * 63) + (0.31 * 65) = 63.62, which is approximately 63.6.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2021>38","subject":"Chemistry","year":"2021","type":"Objective","topic":"STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION","question":"The following ions have the same electron configuration except 8O,12Mg, 13Al, 17Cl","images":[],"options":{"A":"Cl-","B":"O2-","C":"Mg2+","D":"Al3-"},"answer":"A","explanation":"8O2+:2,8  Mg3+: 2,8  12Al2+:2,8  Cl- :2,8,8  it is on Cl- has a different electronic configuration","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2021>39","subject":"Chemistry","year":"2021","type":"Objective","topic":"STRUCTURE OF THE ATOM : ORBITALS","question":"The region around the nucleus where electrons can be located is called","images":[],"options":{"A":"spectra","B":"an orbital","C":"a qaunta","D":"a field"},"answer":"B","explanation":"The region around the nucleus where electrons can be located is called an orbital. An orbital is a region of space where there is a high probability of finding an electron.","marks":"1","difficulty":"1"},{"id":"objective>Chemistry>2021>40","subject":"Chemistry","year":"2021","type":"Objective","topic":"STRUCTURE OF THE ATOM : CHARACTERISTICS AND NATURE OF MATTER.","question":"Proton and electron are called fundamental particles because they","images":[],"options":{"A":"are indivisible","B":"have different changes","C":"are the lightest particles","D":"are found in all matter"},"answer":"D","explanation":"Proton and electron are called fundamental particles because they are found in all matter. Fundamental particles are particles that are not made up of other particles. Protons and electrons are examples of such particles. They are found in all matter because all matter is made up of atoms, and atoms are made up of protons, electrons, and neutrons.","marks":"1","difficulty":"1"},{"id":"objective>Chemistry>2021>41","subject":"Chemistry","year":"2021","type":"Objective","topic":"CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS","question":"The activation energy of the reaction is","images":["data:image/jpeg;base64,"],"options":{"A":"EA","B":"EB","C":"EC","D":"Ep"},"answer":"B","explanation":"Activation energy is the energy possessed by the reacting particles which must b sufficient to overcome the activated complex (energy) of a chemical reaction , hence , it start from the reactant to the activated complex.","marks":"1","difficulty":"3"},{"id":"objective>Chemistry>2021>42","subject":"Chemistry","year":"2021","type":"Objective","topic":"ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY","question":"The enthalpy change of the reaction is","images":["data:image/jpeg;base64,"],"options":{"A":"EA","B":"EB","C":"EC","D":"EP"},"answer":"D","explanation":"Enthalpy change (\u2206H) i the heat change of a chemical reaction   \u2206H = Hp - Hb  Hp - heat of product  Hb - heat of reactant","marks":"1","difficulty":"3"},{"id":"objective>Chemistry>2021>43","subject":"Chemistry","year":"2021","type":"Objective","topic":"ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY","question":"The energy profile diagram illustrates","images":["data:image/jpeg;base64,"],"options":{"A":"an endothermic reaction","B":"an exothermic reaction","C":"a spontaneous reaction","D":"a radius reaction"},"answer":"B","explanation":"\u2206H = Hp - Hb.An exothermic reactant is one which its enthalpy change in negative (-ve) i.e the heat of reactant is greater the heat of product.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2021>44","subject":"Chemistry","year":"2021","type":"Objective","topic":"STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.","question":"How many molecules of oxygen would occupy a volume of 2.24 cm3 at s.t.p?  [Molar volume at s.t.p = 22,400cm3, Avogadro's number = 6.02 x 1023]","images":[],"options":{"A":"3.01 x 1020","B":"3.01 x 1023","C":"6.02 x 1019","D":"6.02 x 1027"},"answer":"C","explanation":"numberofmole=volumemolar mass volume  n = 2.24/22400 = 0.0001mol  Also  n=No of moleculesAvog . constant  0.0001=No of molecules6.02x1023  No of molecules = 6.02x1023 x 0.0001  No of molecules = 6.02 x 1019","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2021>45","subject":"Chemistry","year":"2021","type":"Objective","topic":"STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.","question":"The isotopes of neon are represented by the symbols 20xNe , 21yNe and 22zNe, the relationship between x,y, and z is","images":[],"options":{"A":"x>y>z","B":"x","C":"x = y = z","D":"x"},"answer":"C","explanation":"isotopes are atoms of the same element having the atomic number bu different mass number , hence x,y,and z are the same","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2021>46","subject":"Chemistry","year":"2021","type":"Objective","topic":"CHEMICAL BONDS : INTER MOLECULAR BONDING","question":"Which of the following pairs of molecules form hydrogen bonds?","images":[],"options":{"A":"C2H2OH and CH3OH","B":"CH2OH and H2","C":"H2S and CH3","D":"NH3 and SO3"},"answer":"A","explanation":"Hydrogen bond exist between hydrogen and a highly electro negative non -metal such as nitrogen , chlorine , fluorine or chlorine","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2021>47","subject":"Chemistry","year":"2021","type":"Objective","topic":"CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS","question":"What is the product of the reaction between ethanol and excess acidified KMnO4 solution?","images":[],"options":{"A":"CH2=CH2","B":"CH3COOH","C":"CH3-CH3","D":"CH3OCH3"},"answer":"B","explanation":"Reaction between Alkanol and KMnO4 is oxidation reaction. they are oxidized to give Alkanol and finally Alkanoic acid.  C2H5OH + ([0]) \u2192 Ch3CHO \u2192CH3COOH","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2021>48","subject":"Chemistry","year":"2021","type":"Objective","topic":"CHEMICAL BONDS : IONIC COMPOUNDS","question":"Electrovalent compound normally","images":[],"options":{"A":"have low boiling points","B":"Have mobile electrons","C":"conducts electricity in the solid state","D":"dissolve in polar solvent"},"answer":"D","explanation":"electrovalent compounds   - have high density with high melting and boiling points   - are soluble in polar solvents  - are mostly crystalline in nature","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2021>49","subject":"Chemistry","year":"2021","type":"Objective","topic":"CHEMICAL BONDS : COORDINATE (DATIVE) COVALENT BONDING.","question":"A coordinate covalent bond can be formed between","images":[],"options":{"A":"NH3 and PCl3","B":"HCl3 and AlCl3","C":"BCl3 and NH3","D":"H+ and AlCl3"},"answer":"C","explanation":"A coordinate covalent bond, also known as a dative bond, forms when both electrons in the bond come from the same atom, donating a lone pair of electrons to another atom or molecule that needs electrons to form a bond. NH3 can donate a pair of electrons to form a coordinate bond with BCl3.","marks":"1","difficulty":"1"},{"id":"objective>Chemistry>2021>50","subject":"Chemistry","year":"2021","type":"Objective","topic":"STRUCTURE OF THE ATOM : GROSS FEATURES OF THE ATOM","question":"Which of the following scientist discovered the electron?","images":[],"options":{"A":"Joseph J. Thompson","B":"James chadwick","C":"Amedo Avogadro","D":"Ernest Rutherford"},"answer":"A","explanation":"J.J thomas discovered the electron through his popular experiment called cathode ray experiment , He filled a discharge tube with gas and connected two parallel plates to an e.m.f . At high voltage and low pressure , he discovered a glow from the cathode which consist of beams of electrons","marks":"1","difficulty":"1"}];